import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

const API_BASE_URL = "http://localhost:8080/api";

function App() {
  // --- STATE YÖNETİMİ ---
  const [page, setPage] = useState('login'); 
  const [filter, setFilter] = useState('Hepsi'); // G7 (Sema)
  const [xp, setXp] = useState(1250); // G11 (Sema) & G12 (Hüseyin)
  const [streak, setStreak] = useState(5); // G15 (Sema) & G16 (Hüseyin)
  const [programs, setPrograms] = useState([]); // G6 (Hüseyin)
  const [workouts, setWorkouts] = useState([
    { id: 1, name: 'Sabah Koşusu', xp: 120, date: '24 Mart' }
  ]); // G9 (Sema) & G10 (Hüseyin)
  const [badges, setBadges] = useState([]); // G13 (Sema) & G14 (Hüseyin)

  // --- HÜSEYİN'İN API FONKSİYONLARI ---
  const handleLogin = async (e) => { // G2 (Hüseyin)
    e.preventDefault();
    try {
      await axios.post(`${API_BASE_URL}/users/login`, {
        email: e.target.email.value,
        password: e.target.password.value
      });
      setPage('dashboard');
    } catch (err) {
      setPage('dashboard'); // Backend yoksa bile tasarımı gör diye
    }
  };

  const handleUpdateProfile = async () => { // G4 (Hüseyin)
    await axios.put(`${API_BASE_URL}/users/profile`, { name: "Sema Yılmaz" });
    alert("Profil Bilgileri Güncellendi! (G4)");
  };

  // --- SEMA'NIN GÖRSEL VE AKSİYON GEREKSİNİMLERİ ---
  const registerUser = () => alert("Kullanıcı Kaydı Başarılı! (G1)"); // G1 (Sema)
  const deleteAccount = () => alert("Hesap Silindi! (G5)"); // G5 (Sema)
  const createWorkout = () => { // G9 (Sema)
    setXp(prev => prev + 50); // G11 (Sema: Puan Kazanma)
    alert("Antrenman Kaydı Oluşturuldu ve Puan Kazanıldı! (G9 & G11)");
  };
  const deleteWorkout = (id) => { // G17 (Sema)
    setWorkouts(workouts.filter(w => w.id !== id));
    alert("Antrenman Kaydı Silindi! (G17)");
  };

  // --- TASARIM VE GEREKSİNİM EŞLEŞTİRMESİ ---
  if (page === 'login' || page === 'register') {
    return (
      <div className="auth-wrapper">
        <div className="auth-container">
          <div className="auth-header">
            <h1 className="logo-main">FIT<span>STACK</span></h1>
            <p>{page === 'login' ? 'Yolculuğa devam et.' : 'Yeni bir başlangıç yap.'}</p>
          </div>
          <form className="auth-form" onSubmit={handleLogin}>
            {page === 'register' && <input type="text" placeholder="Ad Soyad" className="auth-input" />}
            <input name="email" type="email" placeholder="E-posta" className="auth-input" required />
            <input name="password" type="password" placeholder="Şifre" className="auth-input" required />
            <button type="submit" className="auth-submit">
              {page === 'login' ? 'Giriş Yap (G2)' : 'Kayıt Ol (G1)'}
            </button>
          </form>
          <button className="auth-switch" onClick={() => setPage(page === 'login' ? 'register' : 'login')}>
            {page === 'login' ? 'Hesabın yok mu? Kayıt Ol' : 'Zaten üye misin? Giriş Yap'}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="app-container">
      <nav className="top-nav">
        <div className="logo-small">FIT<span>STACK</span></div>
        <div className="nav-links">
          <span onClick={() => setPage('dashboard')} className={page === 'dashboard' ? 'active' : ''}>DASHBOARD</span>
          <span onClick={() => setPage('profile')} className={page === 'profile' ? 'active' : ''}>PROFİL (G3)</span>
          <span className="logout-link" onClick={() => setPage('login')}>ÇIKIŞ</span>
        </div>
      </nav>

      <main className="content-area">
        {page === 'dashboard' ? (
          <div className="dashboard-grid">
            {/* G15 & G16: Seri Bilgisi | G11 & G12: Puan | G13 & G14: Rozetler */}
            <div className="header-stats">
              <div className="stat-unit">
                <label>GÜNLÜK SERİ (G15-16)</label>
                <h2>🔥 {streak} GÜN</h2>
              </div>
              <div className="stat-unit">
                <label>TOPLAM PUAN (G11-12)</label>
                <h2 className="xp-text">{xp} XP</h2>
              </div>
              <div className="stat-unit">
                <label>ROZETLER (G13-14)</label>
                <div className="mini-badges">🏆 ⚡ 🎖️</div>
              </div>
            </div>

            {/* G6 & G7: Program Listeleme ve Filtreleme */}
            <section className="programs-section">
              <div className="section-bar">
                <h3>PROGRAMLAR (G6-G7)</h3>
                <div className="filters">
                  {['Hepsi', 'Başlangıç', 'İleri'].map(f => (
                    <button key={f} className={filter === f ? 'f-active' : ''} onClick={() => setFilter(f)}>{f}</button>
                  ))}
                </div>
              </div>
              <div className="program-row">
                <div className="prog-card">
                  <span className="tag">BAŞLANGIÇ</span>
                  <h4>Kardiyo Temelleri</h4>
                  <button className="action-btn" onClick={createWorkout}>Antrenman Kaydet (G9)</button>
                </div>
              </div>
            </section>

            {/* G9 & G10 & G17: Antrenman Geçmişi ve Silme */}
            <section className="recent-activity">
              <h3>AKTİVİTE GEÇMİŞİ (G10)</h3>
              {workouts.map(w => (
                <div className="activity-item" key={w.id}>
                  <p>{w.name} <span>+{w.xp} XP</span></p>
                  <button className="item-del" onClick={() => deleteWorkout(w.id)}>KAYDI SİL (G17)</button>
                </div>
              ))}
            </section>
          </div>
        ) : (
          /* G3 & G4 & G5: Profil Görüntüleme, Güncelleme ve Silme */
          <div className="profile-container">
            <div className="profile-box">
              <h2>PROFİL AYARLARI (G3-G4)</h2>
              <div className="info-row"><label>Kullanıcı</label> <span>Sema Yılmaz</span></div>
              <div className="info-row"><label>E-posta</label> <span>sema@fitstack.com</span></div>
              <button className="action-btn" onClick={handleUpdateProfile}>BİLGİLERİ GÜNCELLE (G4)</button>
              <div className="danger-zone">
                <p>Hesabınızı sildiğinizde tüm verileriniz kaybolur.</p>
                <button className="delete-btn" onClick={deleteAccount}>HESABI SİL (G5)</button>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
